import { defaultProps, defaultOptions } from '../common/component-handler/press-component';
import PressLoadingPlus from '../press-loading-plus/press-loading-plus.vue';
import { getRect } from '../common/dom/rect';
import { getScrollSelector } from '../common/dom/scroll';
import {  SCROLL_VIEW_ID } from './config';
import { vModelMixin } from '../common/vue3/adapter';


const scrollSelector = getScrollSelector(SCROLL_VIEW_ID);


export default {
  name: 'PressList',
  options: {
    ...defaultOptions,
  },
  components: {
    PressLoadingPlus,
  },
  mixins: [vModelMixin],
  props: {
    offset: {
      type: [Number, String],
      default: 50,
    },
    finished: {
      type: Boolean,
      default: false,
    },
    finishedText: {
      type: String,
      default: '',
    },
    loadingText: {
      type: String,
      default: '加载中...',
    },
    immediateCheck: {
      type: Boolean,
      default: true,
    },
    // scrollY: {
    //   type: Boolean,
    //   default: true,
    // },
    enableFlex: {
      type: Boolean,
      default: false,
    },
    enhanced: {
      type: Boolean,
      default: false,
    },
    scrollWithAnimation: {
      type: Boolean,
      default: false,
    },
    enablePassive: {
      type: Boolean,
      default: false,
    },
    scrollAnchoring: {
      type: Boolean,
      default: false,
    },
    // lowerThreshold: {
    //   type: Number,
    //   default: () => 100,
    // },
    // scrollOffset: {
    //   type: Number,
    //   default: () => 0,
    // },
    scrollToElementById: {
      type: String,
      default: '',
    },
    vertical: {
      type: Boolean,
      default: true,
    },
    loadingStyle: {
      type: String,
      default: '',
    },
    loadingSize: {
      type: String,
      default: '20px',
    },
    finishedStyle: {
      type: String,
      default: '',
    },
    ...defaultProps,
  },
  emits: [
    'scroll',
    'input',
    'load',
    'update:modelValue',
  ],
  data() {
    return {
      innerLoading: this.realModelValue,
      SCROLL_VIEW_ID,

      scrollerHeight: 0,
    };
  },
  computed: {
    scrollViewClass() {
      return [this.vertical ? '' : 'press-list--hor', this.customClass].join(' ');
    },
  },
  watch: {
    realModelValue: {
      handler(val) {
        this.innerLoading = val;
        this.check();
      },
    },
    finished: 'check',
  },
  mounted() {
    if (this.immediateCheck) {
      this.check();
    }
  },
  updated() {
  },
  methods: {
    getScrollerHeight() {
      if (this.scrollerHeight) return;

      getRect(this, scrollSelector).then((scrollerRect) => {
        this.scrollerHeight = scrollerRect.height;
      });
    },
    scroll(e) {
      this.getScrollerHeight();
      this.$emit('scroll', e, this.scrollerHeight);
      this.check();
    },
    scrollToLower() {
      // console.log('[scrollToLower]');
      this.emitInput();
    },
    emitInput() {
      if (this.innerLoading || this.finished) return;
      this.innerLoading = true;
      this.emitModelValue(true);
      this.$emit('load');
    },
    check() {
      this.$nextTick(() => {
        this.innerCheck();
      });
    },
    innerCheck() {
      if (this.innerLoading || this.finished) {
        return;
      }

      const { offset }  = this;

      Promise.all([
        getRect(this, '.press-list__placeholder'),
        getRect(this, scrollSelector),
      ]).then((res) => {
        const { 0: placeholderRect, 1: scrollerRect } = res;
        if (this.innerLoading || this.finished) {
          return;
        }

        const scrollerHeight = scrollerRect.bottom - scrollerRect.top;
        if (!scrollerHeight) {
          return;
        }

        let currentOffset = placeholderRect.bottom - scrollerRect.bottom;
        if (!this.vertical) {
          currentOffset = placeholderRect.right - scrollerRect.right;
        }

        const isReachEdge = currentOffset <= offset;
        // console.log('[currentOffset]', currentOffset);

        if (isReachEdge) {
          this.emitInput();
        }
      })
        .catch(() => {})
        .finally(() => {});
    },
  },
};
